const cardNames: Record<number, string> = {
  1: 'Ace', 2: 'Two', 3: 'Three', 4: 'Four', 5: 'Five', 6: 'Six', 7: 'Seven',
  8: 'Eight', 9: 'Nine', 10: 'Ten', 11: 'Page', 12: 'Knight', 13: 'Queen', 14: 'King',
};

function buildMinorArcana(): TarotCard[] {
  const cards: TarotCard[] = [];
  let id = 22;

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const suits: Array<{ suit: 'wands' | 'cups' | 'swords' | 'pentacles'; meanings: Record<number, any> }> = [
    { suit: 'wands', meanings: wandsMeanings },
    { suit: 'cups', meanings: cupsMeanings },
    { suit: 'swords', meanings: swordsMeanings },
    { suit: 'pentacles', meanings: pentaclesMeanings },
  ];

  suits.forEach(({ suit, meanings }) => {
    for (let i = 1; i <= 14; i++) {
      const suitName = suit.charAt(0).toUpperCase() + suit.slice(1);
      const name = `${cardNames[i]} of ${suitName}`;
      const meaning = meanings[i];

      cards.push({
        id: id++,
        name,
        arcana: 'minor',
        suit,
        number: i,
        keywords: meaning.keywords,
        meaningUpright: meaning.upright,
        meaningReversed: meaning.reversed,
        description: meaning.description,
        loveMeaning: meaning.loveMeaning,
        careerMeaning: meaning.careerMeaning,
        reflectionPrompt: meaning.reflectionPrompt,
      });
    }
  });

  return cards;
}

export const minorArcana: TarotCard[] = buildMinorArcana();

export const fullDeck: TarotCard[] = [...majorArcana, ...minorArcana];

/**
 * Draw `count` cards from `deck` without replacement, with a uniform
 * random reversal per card.
 *
 * Uses an in-place Fisher-Yates shuffle: for each position from the end,
 * swap with a uniformly random earlier position. This produces a true
 * uniform permutation — unlike `[...deck].sort(() => Math.random() - 0.5)`,
 * which violates the comparator contract (must be transitive) and yields
 * a non-uniform distribution where some card positions are systematically
 * more likely than others.
 *
 * For seeded / deterministic draws (daily card, share-link readings),
 * use `drawSeededCards` from utils/cardDraw — it accepts a seed and
 * uses the same Fisher-Yates over a seeded PRNG.
 */
export function drawCards(count: number, deck: TarotCard[] = fullDeck): { card: TarotCard; reversed: boolean }[] {
  const shuffled = [...deck];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled.slice(0, count).map(card => ({
    card,
    reversed: Math.random() > 0.5,
  }));
}

// Re-export from utility (eagerly importable without pulling in full deck data)
export { drawSeededCards } from '../utils/cardDraw';

export function getCardById(id: number): TarotCard | undefined {
  return fullDeck.find(card => card.id === id);
}

